SELECT
ID,
WORK_TYPE_CODE,
WORK_TYPE_NAME,
CUSTOMER_NAME,
SHIP_NAME,
BERTH,
PORT_CODE,
PORT_NAME,
REMARK,
STATUS,
CREATE_BY,
CREATE_BY_NAME,
CREATE_TIME,
UPDATE_BY,
UPDATE_BY_NAME,
UPDATE_TIME,
START_TIME,
END_TIME,
PLAN_NO,
CARGO_NAME,
EXAMINE_STATUS,
LOAD_UNLOAD,
WEIGHT_TYPE
FROM
T_WEIGHT_PLAN


        and ID = #{id}


        and WORK_TYPE_CODE = #{workTypeCode}


        and WORK_TYPE_NAME = #{workTypeName}



        and CUSTOMER_NAME LIKE #{customerName_like}



        and SHIP_NAME LIKE #{shipName_like}


        and BERTH = #{berth}


        and PORT_CODE = #{portCode}


        and REMARK = #{remark}



        AND PLAN_NO like #{planNo_like}


        and WEIGHT_TYPE = #{weightType}


        and STATUS = #{status}


        and START_TIME = #{startTime}


        and END_TIME = #{endTime}


ORDER BY PLAN_NO DESC

